// Get array of chats from HTTP Request
const chats = items[0].json.success?.data || items[0].json.data || [];

return chats.map(chat => {

  function convertToISO(raw) {
    if (!raw || typeof raw !== 'string') return null;

    // Handle format: "2025-11-18 19:03:08" -> already ISO
    if (raw.includes('-') && raw.includes(':')) {
      return raw.replace(' ', 'T');
    }

    // Handle format: "18.11.2025 17:37:14"
    if (raw.includes('.')) {
      try {
        const [datePart, timePart] = raw.split(' ');
        const [DD, MM, YYYY] = datePart.split('.');
        return `${YYYY}-${MM}-${DD}T${timePart}`;
      } catch(error) {
        return null;
      }
    }

    return null;
  }

  return {
    json: {
      ...chat,
      createdAtISO: convertToISO(chat.createdAt),
      updatedAtISO: convertToISO(chat.updatedAt),
      completedAtISO: convertToISO(chat.completedAt)
    }
  };
});

