// n8n Code node — "Flatten chat themes (auto-detect)"
// Converts the nested custom_fields array into flat theme/subtheme strings.

const items = $input.all();
const results = [];

const MAIN_THEME_FIELD = 'property_73';

function firstString(v) {
  if (v === undefined || v === null) return '';
  if (Array.isArray(v)) return v.length ? String(v[0]).trim() : '';
  return String(v).trim();
}

function extractThemes(customFields) {
  let theme = '';
  let subtheme = '';
  let subthemeLabel = '';

  if (!Array.isArray(customFields)) {
    return { theme, subtheme, subthemeLabel };
  }

  for (const field of customFields) {
    if (!field || typeof field !== 'object') continue;
    const name = field.name;
    const value = firstString(field.textValue);
    const label = firstString(field.label);
    if (!value) continue;

    if (name === MAIN_THEME_FIELD) {
      theme = value;
    } else {
      if (!subtheme) {
        subtheme = value;
        subthemeLabel = label;
      }
    }
  }

  return { theme, subtheme, subthemeLabel };
}

for (const item of items) {
  const data = item.json;
  if (!data || typeof data !== 'object') continue;

  const { theme, subtheme, subthemeLabel } = extractThemes(data.custom_fields);

  results.push({
    json: {
      chatId: data.id ?? '',
      externalId: data.externalId ?? '',
      agent: data.responsible?.name ?? data.lastMessage?.author?.name ?? '',
      customer: data.author?.name ?? '',
      theme: theme.trim(),
      subtheme: subtheme.trim(),
      subthemeLabel: subthemeLabel.trim(),
      createdAt: data.createdAt ?? '',
      completedAt: data.completedAt ?? '',
    },
  });
}

return results;

const output = [];

function formatTime(posix) {
  if (!posix) return "";
  const date = new Date(posix * 1000);
  const tzOffset = 4 * 60 * 60 * 1000; // GMT+4
  const local = new Date(date.getTime() + tzOffset);
  return local.toISOString().replace("T", " ").substring(0, 19) + " GMT+4";
}

for (const item of items) {
  const messages = item.json.success?.data || item.json.data || [];
  if (!messages.length) continue;

  const filtered = messages.filter(
    m => !m.isSystem && m.content && m.type !== "ai_bot"
  );

  const seen = new Set();
  const unique = filtered.filter(m => {
    const key = `${m.author?.name || ""}-${m.content || ""}-${m.createdAtPosix || ""}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });

  unique.sort((a, b) => (a.createdAtPosix || 0) - (b.createdAtPosix || 0));

  const agentMsg = unique.find(m => m.author?.role?.alias === "agent");
  const agent = agentMsg?.author?.name || "Unknown Agent";
  const customerMsg = unique.find(m => m.author?.role?.alias === "user");
  const customer = customerMsg?.author?.name || "Unknown Customer";

  const chatId = unique[0]?.parentId || item.json.chatId || "unknown";

  const conversation = unique
    .map(m => {
      const ts = formatTime(m.createdAtPosix);
      const author = m.author?.name || "Unknown";
      const text = (m.content || "").trim();
      return `(${ts}) ${author}: ${text}`;
    })
    .join("\n");

  output.push({
    json: { chatId, agent, customer, conversation }
  });
}

return output;

const items = $input.all();
const results = [];

const VALID_SCORES = ['Yes', 'No', 'N/A', 'Check'];

const WEIGHTS = {
  'Greeting and Introduction': 4,
  'Professionalism and Tone': 10,
  'Accuracy and Completeness': 15,
  'Responsiveness and Efficiency': 4,
  'Apologize for Company Error': 3,
  'Clarity and Communication': 7,
  'Verification': 20,
  'Offering Alternatives': 4,
  'KYC': 5,
  'Closure': 3,
  'Thank the Client for Contacting Us': 2,
  'Correct Theme': 5,
  'Escalation Check': 6,
  'Follow-up': 8,
  'Answered All Questions?': 1,
  'Closure Wait Rule Kept?': 3,
};

function normalizeScore(v) {
  if (v === undefined || v === null) return '';
  const s = String(v).trim();
  const match = VALID_SCORES.find(allowed => allowed.toLowerCase() === s.toLowerCase());
  return match || s;
}

function cleanText(v) {
  if (v === undefined || v === null) return '';
  return String(v).replace(/\r\n/g, ' ').replace(/\n/g, ' ').replace(/\t/g, ' ').replace(/\s+/g, ' ').trim();
}

const scoreFields = Object.keys(WEIGHTS);

for (const item of items) {
  let raw = item.json.output;
  if (raw === undefined || raw === null) continue;
  if (typeof raw === 'string' && raw.trim() === '') continue;

  let parsed;
  if (typeof raw === 'object') {
    parsed = raw;
  } else {
    let str = String(raw).trim();
    str = str.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
    const firstBrace = str.indexOf('{');
    const lastBrace = str.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
      str = str.slice(firstBrace, lastBrace + 1);
    }
    if (!str) continue;
    try {
      parsed = JSON.parse(str);
    } catch (err) {
      console.log(`[QA Code Node] Skipped unparseable output: ${err.message}`);
      continue;
    }
  }

  if (!parsed || typeof parsed !== 'object') continue;

  const clean = {
    Agent: cleanText(parsed['Agent']),
    'Chat ID': cleanText(parsed['Chat ID']),
  };

  if (parsed['Closure Wait Rule Kept?'] === undefined && parsed['Closure Wait Rule Violated'] !== undefined) {
    const legacy = String(parsed['Closure Wait Rule Violated']).trim().toLowerCase();
    if (legacy === 'yes') parsed['Closure Wait Rule Kept?'] = 'No';
    else if (legacy === 'no') parsed['Closure Wait Rule Kept?'] = 'Yes';
    else parsed['Closure Wait Rule Kept?'] = parsed['Closure Wait Rule Violated'];
  }

  let totalDeduction = 0;
  const deductions = [];
  for (const f of scoreFields) {
    const score = normalizeScore(parsed[f]);
    clean[f] = score;
    if (score === 'No') {
      const w = WEIGHTS[f];
      totalDeduction += w;
      deductions.push(`${f} (-${w})`);
    }
  }

  clean['First Response Seconds'] = cleanText(parsed['First Response Seconds']);
  clean['Closure Wait Seconds'] = cleanText(parsed['Closure Wait Seconds']);
  clean['DB Theme'] = cleanText(parsed['DB Theme']);
  clean['DB Subtheme'] = cleanText(parsed['DB Subtheme']);
  clean['KB Tool Status'] = cleanText(parsed['KB Tool Status'] ?? parsed['DB Tool Status']);
  clean['Chat ID DB Tool Status'] = cleanText(parsed['Chat ID DB Tool Status']);
  clean['Escalation Tool Status'] = cleanText(parsed['Escalation Tool Status']);
  clean['Sheets Tool Status'] = cleanText(parsed['Sheets Tool Status']);

  const computedScore = Math.max(0, 100 - totalDeduction);
  clean['Score'] = String(computedScore);
  clean['Score Breakdown'] = deductions.length ? deductions.join(', ') : 'No deductions';
  clean['Feedback'] = cleanText(parsed['Feedback']);

  results.push({ json: clean });
}

return results;

